  throw FormatException('Expected bool for $key');
}

bool? _readOptionalBool(Map<String, Object?> json, String key) {
  final value = json[key];
  if (value == null) return null;
  if (value is bool) return value;
  throw FormatException('Expected optional bool for $key');
}

Map<String, Object?> _readRequiredObject(Map<String, Object?> json, String key) {
  final value = json[key];
  if (value is Map) return value.cast<String, Object?>();
  if (value is String) {
    final decoded = jsonDecode(value);
    if (decoded is Map) return decoded.cast<String, Object?>();
  }
  throw FormatException('Expected JSON object for $key');
}

List<Object?> _readRequiredArray(Map<String, Object?> json, String key) {
  final value = json[key];
  if (value is List) return value.cast<Object?>();
  if (value is String) {
    final decoded = jsonDecode(value);
    if (decoded is List) return decoded.cast<Object?>();
  }
  throw FormatException('Expected JSON array for $key');
}
